import { SpecializedTalents, BuildingCategory, Realm } from './types';
import { RECIPES_DATA } from './data/recipes';
import { METHODS_DATA } from './data/methods';
import { BUILDING_TYPES_DATA } from './data/buildings';
import { INITIAL_REGIONS_DATA } from './data/regions';
import { INITIAL_MEMBERS_DATA } from './data/members';
import { PHYSIQUES_LIST, PHYSIQUE_DETAILS_DATA } from './data/physiques';
import { ABILITIES_LIST, ABILITY_DETAILS_DATA } from './data/abilities';
import { TASK_INFO_DATA, DEVELOPMENT_PLANS_DATA } from './data/tasks';
import { GENERATIONS_DATA, SURNAMES_DATA, REALM_ORDER_DATA, SECTS_DATA, POSITIONS_DATA } from './data/metadata';
import { WEAPONS } from './data/weapons';
import { PILLS } from './data/pills';
import { HERBS } from './data/herbs';
import { MINERALS } from './data/minerals';

export interface BuildingMetadata {
    name: string;
    desc: string;
    baseCost: number;
    icon: string;
    category: BuildingCategory;
    baseTurns: number;
    requirements: {
        realm?: Realm;
        talent?: { type: keyof SpecializedTalents['百艺天赋'], rank: number };
    };
}

export const BUILDING_TYPES = BUILDING_TYPES_DATA;
export const RECIPES = RECIPES_DATA;
export const INITIAL_REGIONS = INITIAL_REGIONS_DATA;
export const INITIAL_MEMBERS = INITIAL_MEMBERS_DATA;
export const TASK_INFO = TASK_INFO_DATA;
export const CULTIVATION_METHODS = METHODS_DATA;
export const DEVELOPMENT_PLANS = DEVELOPMENT_PLANS_DATA;
export const GENERATIONS = GENERATIONS_DATA;
export const SURNAMES = SURNAMES_DATA;
export const REALM_ORDER = REALM_ORDER_DATA;
export const PHYSIQUES = PHYSIQUES_LIST;
export const ABILITIES = ABILITIES_LIST;
export const PHYSIQUE_DETAILS = PHYSIQUE_DETAILS_DATA;
export const ABILITY_DETAILS = ABILITY_DETAILS_DATA;
export const SECTS = SECTS_DATA;
export const POSITIONS = POSITIONS_DATA;

/**
 * 分类存放各类物品的详细数据
 */

export const WEAPON_DETAILS = Object.fromEntries(
    WEAPONS.map(w => [w.name, { ...w, category: 'weapon' }])
);

export const PILL_DETAILS = Object.fromEntries(
    PILLS.map(p => [p.name, { ...p, category: 'pill', effect: '服用后产生对应增益', gradeText: `${p.grade}品丹药` }])
);

export const HERB_DETAILS = Object.fromEntries(
    HERBS.map(h => [h.name, { ...h, category: 'herb', gradeText: `${h.grade}品灵药` }])
);

export const MINERAL_DETAILS = Object.fromEntries(
    MINERALS.map(m => [m.name, { ...m, category: 'mineral', gradeText: `${m.grade}品灵矿` }])
);

export const METHOD_DETAILS = Object.fromEntries(
    METHODS_DATA.map(m => [m.name, { 
        ...m, 
        category: 'method', 
        effect: m.bonus, 
        gradeText: `${m.grade}品${m.quality}` 
    }])
);

/**
 * 获取百艺加成 (基于基础天赋属性 1-10)
 */
export const getArtisanBonus = (talentLevel: number): number => {
    if (talentLevel <= 5) return 0;
    if (talentLevel === 6) return 2;
    if (talentLevel === 7) return 5;
    if (talentLevel === 8) return 7;
    if (talentLevel === 9) return 10;
    if (talentLevel === 10) return 15;
    return 0;
};

/**
 * 获取武器天赋熟练度获取加成 (1-10)
 */
export const getWeaponTalentBonus = (talentLevel: number): number => {
    if (talentLevel <= 5) return 0;
    if (talentLevel === 6) return 2;
    if (talentLevel === 7) return 5;
    if (talentLevel === 8) return 7;
    if (talentLevel === 9) return 10;
    if (talentLevel === 10) return 20;
    return 0;
};

/**
 * 获取武器等级称号 (基于熟练度)
 */
export const getWeaponMasteryTitle = (type: string, proficiency: number): string => {
    if (proficiency < 100) return `${type}初学`;
    if (proficiency < 500) return `${type}小成`;
    if (proficiency < 1000) return `${type}大成`;
    if (proficiency < 2500) return `${type}圆满`;
    if (proficiency < 5000) return `${type.replace('法', '道')}大师`;
    return `${type.replace('法', '道')}宗师`;
};

/**
 * 获取职业等级称号 (完全基于熟练度)
 */
export const getArtisanTitle = (type: string, proficiency: number): string => {
    const getThreshold = (rank: number): number => {
        if (rank <= 0) return 0;
        if (rank === 1) return 10;
        return 10 + 50 * rank * (rank - 1);
    };

    if (proficiency < getThreshold(1)) return `${type}学徒`;

    let currentRank = 1;
    for (let r = 9; r >= 1; r--) {
        if (proficiency >= getThreshold(r)) {
            currentRank = r;
            break;
        }
    }

    const numerals = ['', '一', '二', '三', '四', '五', '六', '七', '八', '九'];
    return `${numerals[currentRank]}品${type}师`;
};

import React, { useState, useMemo, useCallback } from 'react';
/* Added SpecializedTalents to the import list from types to resolve the 'Cannot find name' error on line 601 */
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, CultivationMethod, MethodType, TalentTier, RootGrade, SpecializedTalents } from '../types';
import { 
    TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, POSITIONS, 
    PHYSIQUE_DETAILS, ABILITY_DETAILS, getArtisanTitle, getArtisanBonus, 
    getWeaponMasteryTitle, getWeaponTalentBonus, 
    WEAPON_DETAILS, PILL_DETAILS, HERB_DETAILS, MINERAL_DETAILS, METHOD_DETAILS 
} from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
}

const ITEMS_PER_PAGE = 8;

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'tasks' | 'cultivation' | 'plan' | 'bag'>('attr');
    const [bagSubTab, setBagSubTab] = useState<'equipment' | 'pills' | 'materials' | 'methods'>('equipment');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedEquipSlot, setFocusedEquipSlot] = useState<string | null>(null);
    const [focusedBagItem, setFocusedBagItem] = useState<string | null>(null);
    // Fixed type for focusedLibraryMethodId to number | null to match CultivationMethod.id
    const [focusedLibraryMethodId, setFocusedLibraryMethodId] = useState<number | null>(null);

    // Tooltip State
    const [tooltip, setTooltip] = useState<{
        content: React.ReactNode;
        x: number;
        y: number;
        visible: boolean;
    } | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    // 评级色彩逻辑
    const getTierColor = (tier: TalentTier) => {
        switch (tier) {
            case '凡人': return 'text-slate-400';
            case '平庸': return 'text-gray-300';
            case '普通': return 'text-emerald-500';
            case '超凡': return 'text-sky-500';
            case '天才': return 'text-purple-500';
            case '绝世': return 'text-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.4)]';
            case '绝世天骄': return 'text-rose-500 animate-pulse font-black shadow-[0_0_12px_rgba(244,63,94,0.6)]';
            default: return 'text-gray-400';
        }
    };

    // 称号颜色逻辑 (白, 绿, 蓝, 紫, 橙, 金, 红)
    const getTitleColor = (tier: TalentTier) => {
        switch (tier) {
            case '凡人': return 'text-white';
            case '平庸': return 'text-green-500';
            case '普通': return 'text-blue-400';
            case '超凡': return 'text-purple-500';
            case '天才': return 'text-orange-500';
            case '绝世': return 'text-amber-400';
            case '绝世天骄': return 'text-red-600';
            default: return 'text-white';
        }
    };

    const getRootGradeColor = (grade: RootGrade) => {
        switch (grade) {
            case '凡人': return 'text-slate-500';
            case '伪灵根': return 'text-gray-400';
            case '下品灵根': return 'text-emerald-600';
            case '中品灵根': return 'text-sky-600';
            case '极品灵根': return 'text-amber-600 font-bold';
            default: return 'text-gray-400';
        }
    };

    const getGradeColor = (grade: number | string | undefined) => {
        if (typeof grade === 'string') return 'border-purple-500 text-purple-400 shadow-[0_0_5px_rgba(168,85,247,0.3)]';
        const g = Number(grade) || 0;
        if (g <= 1) return 'border-slate-300 text-slate-100 bg-slate-500/10 shadow-[0_0_5px_rgba(255,255,255,0.1)]';
        if (g <= 4) return 'border-emerald-500 text-emerald-400 bg-emerald-500/10 shadow-[0_0_8px_rgba(16,185,129,0.2)]';
        if (g <= 6) return 'border-sky-500 text-sky-400 bg-sky-500/10 shadow-[0_0_10px_rgba(14,165,233,0.3)]';
        if (g === 7) return 'border-orange-500 text-orange-400 bg-orange-500/10 shadow-[0_0_12px_rgba(249,115,22,0.4)]';
        if (g >= 8) return 'border-yellow-500 text-yellow-400 bg-yellow-500/10 shadow-[0_0_15px_rgba(234,179,8,0.5)]';
        return 'border-slate-400 text-slate-300';
    };

    const getRealmStyle = (realm: Realm) => {
        if (realm === Realm.Mortal) return "border-[#4a3728] bg-[#2c1810] text-[#8c6b4f]";
        return "border-[#6b4e31] bg-[#3d2b1f] text-[#c9a063]";
    };

    const getRealmText = (realm: Realm, subRealm: number) => {
        if (realm === Realm.Mortal) return '凡人';
        return `${realm}${subRealm}层`;
    };

    const getGradeText = (method: CultivationMethod) => {
        const numerals = ['','一','二','三','四','五','六','七','八','九'];
        return `${numerals[method.grade]}品${method.quality}`;
    };

    // Changed methodId type to number to fix string assignment errors
    const toggleMethod = (methodId: number, type: MethodType) => {
        if (!selectedMember) return;

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
        setFocusedLibraryMethodId(null);
    };

    const getElementColorClass = (key: string, val: number) => {
        if (val === 0) return 'text-gray-600 border-gray-800 opacity-30';
        switch (key) {
            case 'gold': return 'text-yellow-400 border-yellow-500 bg-yellow-500/10';
            case 'wood': return 'text-green-400 border-green-500 bg-green-500/10';
            case 'water': return 'text-blue-400 border-blue-500 bg-blue-500/10';
            case 'fire': return 'text-red-400 border-red-500 bg-red-500/10';
            case 'earth': return 'text-orange-700 border-orange-800 bg-orange-800/10';
            default: return 'text-gray-400 border-gray-500';
        }
    };

    const getElementName = (key: string) => {
        switch (key) {
            case 'gold': return '金';
            case 'wood': return '木';
            case 'water': return '水';
            case 'fire': return '火';
            case 'earth': return '土';
            default: return key;
        }
    };

    // 核心逻辑修改：过滤出“已拥有”的功法，并包含其总持有数
    const libraryMethods = useMemo(() => {
        if (!selectedMember) return [];
        return CULTIVATION_METHODS.filter(m => {
            // 类型匹配
            if (m.type !== libraryType) return false;

            // 检查是否拥有：家族仓库、个人行囊、或已装备
            const isOwnedByClan = (state.inventory.methods[m.name] || 0) > 0;
            const isOwnedBySelf = (selectedMember.personalInventory.methods[m.name] || 0) > 0;
            const isEquipped = selectedMember.mainMethodId === m.id || 
                             selectedMember.movementMethodId === m.id || 
                             selectedMember.auxMethodIds.includes(m.id);

            return isOwnedByClan || isOwnedBySelf || isEquipped;
        }).map(m => {
            const totalCount = (state.inventory.methods[m.name] || 0) + (selectedMember.personalInventory.methods[m.name] || 0);
            return { ...m, totalCount };
        });
    }, [libraryType, selectedMember, state.inventory.methods]);

    // Global Tooltip Management
    const showTooltip = useCallback((e: React.MouseEvent, content: React.ReactNode) => {
        const rect = e.currentTarget.getBoundingClientRect();
        let x = rect.left + rect.width / 2;
        let y = rect.top;

        if (rect.top < 300) {
            y = rect.bottom + 12;
        } else {
            y = rect.top - 12;
        }

        const tooltipWidth = 260;
        if (x - tooltipWidth / 2 < 20) x = tooltipWidth / 2 + 20;
        if (x + tooltipWidth / 2 > window.innerWidth - 20) x = window.innerWidth - tooltipWidth / 2 - 20;

        setTooltip({ content, x, y, visible: true });
    }, []);

    const hideTooltip = useCallback(() => {
        setTooltip(prev => prev ? { ...prev, visible: false } : null);
    }, []);

    const renderMethodTooltipContent = (method: CultivationMethod) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-yellow-500 font-bold text-sm">{method.name}</span>
                <span className={`text-[10px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(method.grade)}`}>
                    {getGradeText(method)}
                </span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{method.desc}</p>
            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-green-500 font-bold mb-1">【功法效果】</p>
                {method.buffs.cultivationSpeed && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">修炼速度</span>
                        <span className={method.buffs.cultivationSpeed > 0 ? 'text-green-400' : 'text-red-400'}>
                            {method.buffs.cultivationSpeed > 0 ? '+' : ''}{method.buffs.cultivationSpeed}%
                        </span>
                    </div>
                )}
                {method.buffs.attack && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">战斗力</span>
                        <span className="text-orange-400">+{method.buffs.attack}%</span>
                    </div>
                )}
                {method.buffs.defense && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">防御力</span>
                        <span className="text-blue-400">+{method.buffs.defense}%</span>
                    </div>
                )}
                {method.buffs.maxAge && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">延寿</span>
                        <span className="text-emerald-400">+{method.buffs.maxAge} 载</span>
                    </div>
                )}
                <p className="text-[9px] text-yellow-600/80 mt-2 italic">"{method.bonus}"</p>
            </div>
        </div>
    );

    const renderItemTooltipContent = (itemName: string) => {
        const details = WEAPON_DETAILS[itemName] || 
                        PILL_DETAILS[itemName] || 
                        HERB_DETAILS[itemName] || 
                        MINERAL_DETAILS[itemName] || 
                        METHOD_DETAILS[itemName];

        if (!details) return (
            <div className="w-52 sm:w-64 font-serif border-2 border-red-900/30 p-2 bg-black/40">
                <span className="text-gray-500 text-xs">未知物品：{itemName}</span>
            </div>
        );

        const gradeStr = (details as any).gradeText || (details.grade ? (typeof details.grade === 'number' ? `${details.grade}品` : details.grade) : '凡物');

        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{itemName}</span>
                    <span className={`text-[9px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(details.grade)}`}>
                        {gradeStr}
                    </span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{details.desc}</p>
                {details.effect && (
                    <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                        <p className="text-[10px] text-orange-400 font-bold mb-1">【物品效果】</p>
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">效果描述</span>
                            <span className="text-gray-200">{details.effect}</span>
                        </div>
                    </div>
                )}
            </div>
        );
    };

    const handleUnequip = (slot: keyof ClanMember['equippedItems']) => {
        if (!selectedMember) return;
        const itemName = selectedMember.equippedItems[slot];
        if (!itemName) return;

        const newEquipped = { ...selectedMember.equippedItems, [slot]: null };
        const newInventory = { ...selectedMember.personalInventory };

        // 简单处理：如果是武器，放入武器库，否则放入对应分类
        if (slot === 'weapon') {
            newInventory.weapons[itemName] = (newInventory.weapons[itemName] || 0) + 1;
        } else {
            // 目前简化为统一放回
            newInventory.weapons[itemName] = (newInventory.weapons[itemName] || 0) + 1;
        }

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedEquipSlot(null);
    };

    const handleEquip = (itemName: string, category: 'weapon' | 'armor' | 'accessory' | 'treasure') => {
        if (!selectedMember) return;

        const newEquipped = { ...selectedMember.equippedItems };
        const newInventory = { ...selectedMember.personalInventory };

        // 卸下当前槽位的装备
        const currentItem = newEquipped[category];
        if (currentItem) {
            newInventory.weapons[currentItem] = (newInventory.weapons[currentItem] || 0) + 1;
        }

        // 扣除行囊中的新装备
        if (newInventory.weapons[itemName] > 0) {
            newInventory.weapons[itemName]--;
            if (newInventory.weapons[itemName] === 0) delete newInventory.weapons[itemName];
        }

        // 佩戴
        newEquipped[category] = itemName;

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedBagItem(null);
    };

    // 丹药使用逻辑
    const handleUsePill = (pillName: string) => {
        if (!selectedMember) return;
        const newInventory = { ...selectedMember.personalInventory };
        if (!newInventory.pills[pillName] || newInventory.pills[pillName] <= 0) return;

        // 扣除消耗
        newInventory.pills[pillName]--;
        if (newInventory.pills[pillName] === 0) delete newInventory.pills[pillName];

        const updates: Partial<ClanMember> = { personalInventory: newInventory };

        // 效果解析
        switch (pillName) {
            case '凝气丹':
                updates.cultivationProgress = Math.min(100, selectedMember.cultivationProgress + 15);
                break;
            case '养元丹':
                updates.status = 'healthy';
                updates.maxAge = selectedMember.maxAge + 1; // 固本培元，延寿一载
                break;
            case '通脉丹':
                updates.cultivationProgress = Math.min(100, selectedMember.cultivationProgress + 10);
                // 永久微量增加神识
                updates.divineSense = selectedMember.divineSense + 1;
                break;
        }

        onUpdateMember(selectedMember.id, updates);
        setFocusedBagItem(null);
        hideTooltip();
    };

    const renderPhysiqueTooltipContent = (physique: string) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-pink-400 font-bold text-sm">{physique}</span>
                <span className="text-[9px] px-1.5 py-0.5 rounded-sm font-bold border border-pink-900/50 text-pink-500">天赋体质</span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{PHYSIQUE_DETAILS[physique] || '暂无详细记载。'}</p>
            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-pink-500 font-bold mb-1">【先天禀赋】</p>
                <div className="flex justify-between text-[10px]">
                    <span className="text-gray-500">觉醒状态</span>
                    <span className="text-emerald-400">已圆满</span>
                </div>
            </div>
        </div>
    );

    const renderAbilityTooltipContent = (ability: string) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-orange-400 font-bold text-sm">{ability}</span>
                <span className="text-[9px] px-1.5 py-0.5 rounded-sm font-bold border border-orange-900/50 text-orange-500">神通秘术</span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{ABILITY_DETAILS[ability] || '暂无详细记载。'}</p>
            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-orange-500 font-bold mb-1">【神通威力】</p>
                <div className="flex justify-between text-[10px]">
