                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-3 animate-fade-in max-w-2xl mx-auto pr-2">
                                            {(Object.keys(TASK_INFO) as TaskType[]).map(task => (
                                                <button
                                                    key={task}
                                                    onClick={() => onUpdateMember(selectedMember.id, { assignment: task })}
                                                    className={`w-full p-6 rounded-2xl border transition-all text-left shadow-lg ${selectedMember.assignment === task ? 'bg-yellow-900/20 border-yellow-500 text-yellow-100 ring-1 ring-yellow-500/50' : 'bg-black/30 border-white/5 hover:bg-black/50 hover:border-white/20 text-gray-400'}`}
                                                >
                                                    <p className="text-base font-bold mb-1">{TASK_INFO[task].label}</p>
                                                    <p className="text-xs opacity-60 leading-relaxed">{TASK_INFO[task].desc}</p>
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

