                                                        <div key={key} className="flex flex-col items-center gap-2">
                                                            <div className={`w-10 h-10 sm:w-14 sm:h-14 rounded-full border-2 flex items-center justify-center ${getElementColorClass(key, val)} shadow-xl`}>
