                                                            </div>
                                                            <span className={`text-sm font-bold ${val > 0 ? getElementColorClass(key, val).split(' ')[0] : 'text-gray-800'}`}>{val}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {detailTab === 'bag' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-8 animate-fade-in pr-2">
                                            <div className="flex flex-wrap gap-2 p-1 bg-black/40 rounded-xl border border-yellow-900/20 w-fit">
                                                <button onClick={() => setBagSubTab('equipment')} className={`px-4 sm:px-6 py-2 text-xs rounded-lg transition-all font-bold ${bagSubTab === 'equipment' ? 'bg-yellow-800 text-yellow-100 shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>🏮 装备</button>
                                                <button onClick={() => setBagSubTab('pills')} className={`px-4 sm:px-6 py-2 text-xs rounded-lg transition-all font-bold ${bagSubTab === 'pills' ? 'bg-pink-900/40 text-pink-200' : 'text-gray-500 hover:text-gray-300'}`}>💊 丹药</button>
                                                <button onClick={() => setBagSubTab('materials')} className={`px-4 sm:px-6 py-2 text-xs rounded-lg transition-all font-bold ${bagSubTab === 'materials' ? 'bg-emerald-900/40 text-emerald-200' : 'text-gray-500 hover:text-gray-300'}`}>🎋 材料</button>
                                                <button onClick={() => setBagSubTab('methods')} className={`px-4 sm:px-6 py-2 text-xs rounded-lg transition-all font-bold ${bagSubTab === 'methods' ? 'bg-amber-900/40 text-amber-200' : 'text-gray-500 hover:text-gray-300'}`}>📜 功法</button>
                                            </div>

                                            <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-5 gap-4">
                                                {bagSubTab === 'equipment' && (
                                                    Object.entries(selectedMember.personalInventory.weapons).length > 0 ? Object.entries(selectedMember.personalInventory.weapons).map(([name, count]) => 
                                                        renderBagItem('⚔️', name, count, 'bg-[#1a1812]', 'border-[#4d3d1d]', 'hover:border-[#ff9c38]', () => handleEquip(name, 'weapon'), '佩戴')
                                                    ) : <div className="col-span-full py-24 text-center text-gray-700 italic border-2 border-dashed border-white/5 rounded-xl">行囊中暂无兵刃</div>
                                                )}

                                                {bagSubTab === 'pills' && (
                                                    Object.entries(selectedMember.personalInventory.pills).length > 0 ? Object.entries(selectedMember.personalInventory.pills).map(([name, count]) => 
                                                        renderBagItem('💊', name, count, 'bg-[#1a1215]', 'border-[#4d1d2d]', 'hover:border-[#ff3870]', () => handleUsePill(name), '服用')
                                                    ) : <div className="col-span-full py-24 text-center text-gray-700 italic border-2 border-dashed border-white/5 rounded-xl">尚未携带任何灵丹</div>
                                                )}

                                                {bagSubTab === 'materials' && (
                                                    <>
                                                        {Object.entries(selectedMember.personalInventory.herbs).map(([name, count]) => renderBagItem('🌿', name, count, 'bg-[#121a15]', 'border-[#1d4d3a]', 'hover:border-[#38ff9c]'))}
                                                        {Object.entries(selectedMember.personalInventory.minerals).map(([name, count]) => renderBagItem('💎', name, count, 'bg-[#121620]', 'border-[#1d2d4d]', 'hover:border-[#3894ff]'))}
                                                        {(Object.entries(selectedMember.personalInventory.herbs).length === 0 && Object.entries(selectedMember.personalInventory.minerals).length === 0) && (
                                                            <div className="col-span-full py-24 text-center text-gray-700 italic border-2 border-dashed border-white/5 rounded-xl">行囊空空如也</div>
                                                        )}
                                                    </>
                                                )}

                                                {bagSubTab === 'methods' && (
                                                    Object.entries(selectedMember.personalInventory.methods).length > 0 ? Object.entries(selectedMember.personalInventory.methods).map(([name, count]) => {
                                                        const mData = CULTIVATION_METHODS.find(m => m.name === name);
                                                        // Fixed isEquipped calculation to safely handle potentially undefined mData
                                                        const isEquipped = mData ? (selectedMember.mainMethodId === mData.id || selectedMember.movementMethodId === mData.id || selectedMember.auxMethodIds.includes(mData.id)) : false;
                                                        return renderBagItem('📜', name, count, 'bg-[#12110c]', mData ? getGradeColor(mData.grade) : 'border-amber-900/20', isEquipped ? 'opacity-40' : 'hover:border-[#f5d442]', 
                                                            mData && !isEquipped ? () => { toggleMethod(mData.id, mData.type); setFocusedBagItem(null); } : undefined, '研习');
                                                    }) : <div className="col-span-full py-24 text-center text-gray-700 italic border-2 border-dashed border-white/5 rounded-xl">行囊中暂无秘籍</div>
                                                )}
                                            </div>
                                        </div>
                                    )}

                                    {detailTab === 'talents' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-10 animate-fade-in text-white pr-2">
                                            <div>
                                                <h4 className="text-red-700 text-[15px] font-bold uppercase tracking-[0.3em] border-b border-red-900/20 pb-2 mb-6">⚔️ 战斗造诣</h4>
                                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                                                    {(Object.entries(selectedMember.talents.战斗天赋) as [string, number][]).filter(([_, val]) => val > 0).map(([key, val]) => {
                                                        const prof = selectedMember.combatProficiencies[key as keyof SpecializedTalents['战斗天赋']] || 0;
                                                        const title = getWeaponMasteryTitle(key, prof);
                                                        const bonus = getWeaponTalentBonus(val);
                                                        return (
                                                            <div key={key} className="bg-black/30 p-4 rounded-xl border border-white/5 relative group shadow-lg">
                                                                <div className="flex justify-between items-center mb-2">
                                                                    <span className="text-[11px] text-gray-400 font-bold">{key}天赋</span>
                                                                    <span className="text-xl font-bold text-red-500 font-mono">{val}</span>
                                                                </div>
                                                                <p className="text-sm font-bold text-orange-400 mb-2">{title}</p>
                                                                <div className="flex justify-between text-[11px] mb-2">
                                                                    <span className="text-gray-500">当前熟练度:</span>
                                                                    <span className="text-gray-200 font-mono">{prof}</span>
                                                                </div>
                                                                {bonus > 0 && <p className="text-[10px] text-green-500 font-bold">习练加成: +{bonus}%</p>}
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                            <div>
                                                <h4 className="text-blue-600 text-[15px] font-bold uppercase tracking-[0.3em] border-b border-blue-900/20 pb-2 mb-6">🧪 百艺修持</h4>
                                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                                                    {(Object.entries(selectedMember.talents.百艺天赋) as [string, number][]).filter(([_, val]) => val > 0).map(([key, val]) => {
                                                        const prof = selectedMember.proficiencies[key as keyof SpecializedTalents['百艺天赋']] || 0;
                                                        const title = getArtisanTitle(key, prof);
                                                        const successBonus = getArtisanBonus(val);
                                                        return (
                                                            <div key={key} className="bg-black/30 p-5 rounded-xl border border-blue-900/20 relative group overflow-hidden shadow-lg">
                                                                <div className="flex justify-between items-center mb-3">
                                                                    <span className="text-[11px] text-gray-400 font-bold">{key}天赋</span>
                                                                    <span className="text-xl font-bold text-blue-500 font-mono">{val}</span>
                                                                </div>
                                                                <p className="text-sm font-bold text-yellow-500 mb-2">{title}</p>
                                                                <div className="flex justify-between items-center text-[11px] mb-2">
                                                                    <span className="text-gray-500">当前熟练度:</span>
                                                                    <span className="text-blue-300 font-mono">{prof}</span>
                                                                </div>
                                                                {successBonus > 0 && <p className="text-[11px] text-green-500 font-bold">属性加成: +{successBonus}%</p>}
                                                                <div className="absolute -bottom-4 -right-4 opacity-5 text-5xl group-hover:scale-110 group-hover:rotate-12 transition-all">⚙️</div>
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {detailTab === 'cultivation' && renderCultivationTab()}

                                    {detailTab === 'plan' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-3 animate-fade-in max-w-2xl mx-auto pr-2">
                                            {(Object.keys(DEVELOPMENT_PLANS) as DevelopmentPlan[]).map(planKey => (
                                                <button
                                                    key={planKey}
                                                    onClick={() => onUpdateMember(selectedMember.id, { developmentPlan: planKey })}
                                                    className={`w-full p-6 rounded-2xl border transition-all text-left shadow-lg ${selectedMember.developmentPlan === planKey ? 'bg-purple-900/20 border-purple-500 ring-1 ring-purple-500/50' : 'bg-black/30 border-white/5 hover:bg-black/50 hover:border-white/20'}`}
                                                >
                                                    <p className="text-base font-bold text-white mb-1">{DEVELOPMENT_PLANS[planKey].label}</p>
                                                    <p className="text-xs text-gray-500 leading-relaxed">{DEVELOPMENT_PLANS[planKey].desc}</p>
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                    {detailTab === 'tasks' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-3 animate-fade-in max-w-2xl mx-auto pr-2">
                                            {(Object.keys(TASK_INFO) as TaskType[]).map(task => (
                                                <button
                                                    key={task}
                                                    onClick={() => onUpdateMember(selectedMember.id, { assignment: task })}
                                                    className={`w-full p-6 rounded-2xl border transition-all text-left shadow-lg ${selectedMember.assignment === task ? 'bg-yellow-900/20 border-yellow-500 text-yellow-100 ring-1 ring-yellow-500/50' : 'bg-black/30 border-white/5 hover:bg-black/50 hover:border-white/20 text-gray-400'}`}
                                                >
                                                    <p className="text-base font-bold mb-1">{TASK_INFO[task].label}</p>
                                                    <p className="text-xs opacity-60 leading-relaxed">{TASK_INFO[task].desc}</p>
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ClanDashboard;

export enum Realm {
    Mortal = '凡人',
    QiRefinement = '练气',
    FoundationEstablishment = '筑基',
    Zifu = '紫府',
    JinDan = '金丹',
    YuanYing = '元婴',
    YuanShen = '化神'
}

export enum Element {
    Gold = '金',
    Wood = '木',
    Water = '水',
    Fire = '火',
    Earth = '土'
}

export type TaskType = 'Cultivation' | 'Exploration' | 'Research' | 'Patrol' | 'Idle' | 'Mission';
export type TalentTier = '凡人' | '平庸' | '普通' | '超凡' | '天才' | '绝世' | '绝世天骄';
export type RootGrade = '凡人' | '伪灵根' | '下品灵根' | '中品灵根' | '极品灵根';
export type DevelopmentPlan = 'Combat' | 'Alchemy' | 'Smithing' | 'Talisman' | 'Balanced';
export type MethodQuality = '上等' | '中等' | '下等';
export type MethodType = 'Cultivation' | 'Combat' | 'Movement';

export type BuildingCategory = 'Resource' | 'Functional' | 'Base';

export interface Building {
    id: string;
    type: string;
    level: number;
    assignedMemberId: string | null;
    isFinished: boolean;
    turnsRemaining: number;
    activeProduction?: {
        recipeName: string;
        turnsRemaining: number;
        type: 'Alchemy' | 'Smithing';
    };
}

export interface Inventory {
    herbs: Record<string, number>;
    minerals: Record<string, number>;
    paper: number;
    pills: Record<string, number>;
    weapons: Record<string, number>;
    methods: Record<string, number>;
    scrolls: Record<string, number>;
}

export interface MethodBuffs {
    cultivationSpeed?: number;
    attack?: number;
    defense?: number;
    divineSense?: number;
    maxAge?: number;
}

export interface CultivationMethod {
    id: number;
    name: string;
    grade: number;
    quality: MethodQuality;
    type: MethodType;
    element: Element | '无';
    desc: string;
    bonus: string;
    buffs: MethodBuffs;
}

export interface ElementalRoots {
    gold: number;
    wood: number;
    water: number;
    fire: number;
    earth: number;
}

export interface SpecializedTalents {
    战斗天赋: {
        剑法: number;
        拳法: number;
        枪法: number;
        刀法: number;
        弓箭: number;
    };
    百艺天赋: {
        炼丹: number;
        炼器: number;
        制符: number;
        阵法: number;
    };
}

export interface ClanMember {
    id: string;
    name: string;
    title?: string; 
    gender: '男' | '女';
    generation: number; 
    realm: Realm;
    subRealm: number; 
    age: number;
    maxAge: number;
    physique: string;
    aptitude: number;
    comprehension: number;
    divineSense: number;
    roots: ElementalRoots;
    rootGrade: RootGrade;
    talents: SpecializedTalents;
    proficiencies: Record<keyof SpecializedTalents['百艺天赋'], number>;
    combatProficiencies: Record<keyof SpecializedTalents['战斗天赋'], number>;
    tier: TalentTier;

    element: Element;
    status: 'healthy' | 'injured' | 'dead';
    loyalty: number; 
    assignment: TaskType;
    legacyPoints: number; 
    deathYear?: number;

    mainMethodId: number | null;
    movementMethodId: number | null;
    auxMethodIds: number[];

    equippedItems: {
        weapon: string | null;
        armor: string | null;
        accessory: string | null;
        treasure: string | null;
    };
    personalInventory: Inventory;

    cultivationProgress: number;
    developmentPlan: DevelopmentPlan;
    divineAbilities: string[];
    sect: string;
    position: string;

    // Relationships
    fatherId?: string | null;
    motherId?: string | null;
    spouseId?: string | null;
    mentorId?: string | null;
}

export type RegionCategory = 'Natural' | 'Stakeholder' | 'Mystic' | 'Resource';
export type RegionType = 'lake' | 'mountain' | 'forest' | 'city' | 'sect' | 'ruins' | 'cave' | 'island' | 'desert' | 'mine' | 'field';

export type FactionType = '望月李氏' | '北寒宗' | '天一剑宗' | '邵家' | '魏家' | '离火门' | '南海散修' | '无';

export interface Region {
    id: string;
    name: string;
    description: string;
    difficulty: number;
    owner: FactionType;
    x: number;
    y: number;
    type: RegionType;
    category: RegionCategory;
    isDiscovered: boolean;
    resources: string[];

    // 领土控制逻辑
    controlValue: number; // 0-100, 李家控制力
    occupancyStatus: 'idle' | 'contested' | 'secured'; 

    // 产出配置
    production?: {
        stones?: number;
        merit?: number;
        items?: Record<string, number>;
    };

    activeMission?: {
        memberId: string;
        turnsRemaining: number;
        totalTurns: number;
        type: 'Occupy' | 'Explore' | 'War' | 'Mystic';
    };

    // 临时点位标记
    isTemporary?: boolean;
    expiryYear?: number;
}

export interface GameState {
    year: number;
    spiritStones: number;
    merit: number; 
    luck: number; 
    members: ClanMember[];
    regions: Region[];
    buildings: Building[];
    inventory: Inventory;
    currentRegionId: string;
    isMirrorActive: boolean;
    logs: string[];
    heritagePool: number;
}

import React, { useState, useMemo, useCallback } from 'react';
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, CultivationMethod, MethodType, TalentTier, RootGrade, SpecializedTalents } from '../types';
import { 
    TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, POSITIONS, 
    PHYSIQUE_DETAILS, ABILITY_DETAILS, getArtisanTitle, getArtisanBonus, 
    getWeaponMasteryTitle, getWeaponTalentBonus, 
    WEAPON_DETAILS, PILL_DETAILS, HERB_DETAILS, MINERAL_DETAILS, METHOD_DETAILS,
    GENERATIONS
} from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
}

const ITEMS_PER_PAGE = 8;

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'tasks' | 'cultivation' | 'plan' | 'bag' | 'relations'>('attr');
    const [bagSubTab, setBagSubTab] = useState<'equipment' | 'pills' | 'materials' | 'methods'>('equipment');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedEquipSlot, setFocusedEquipSlot] = useState<string | null>(null);
    const [focusedBagItem, setFocusedBagItem] = useState<string | null>(null);
    const [focusedLibraryMethodId, setFocusedLibraryMethodId] = useState<number | null>(null);

    // Tooltip State
    const [tooltip, setTooltip] = useState<{
        content: React.ReactNode;
        x: number;
        y: number;
        visible: boolean;
    } | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    // 评级色彩逻辑
    const getTierColor = (tier: TalentTier) => {
        switch (tier) {
            case '凡人': return 'text-slate-400';
            case '平庸': return 'text-gray-300';
            case '普通': return 'text-emerald-500';
            case '超凡': return 'text-sky-500';
            case '天才': return 'text-purple-500';
            case '绝世': return 'text-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.4)]';
            case '绝世天骄': return 'text-rose-500 animate-pulse font-black shadow-[0_0_12px_rgba(244,63,94,0.6)]';
            default: return 'text-gray-400';
        }
    };

    const getTitleColor = (tier: TalentTier) => {
        switch (tier) {
            case '凡人': return 'text-white';
            case '平庸': return 'text-green-500';
            case '普通': return 'text-blue-400';
            case '超凡': return 'text-purple-500';
            case '天才': return 'text-orange-500';
            case '绝世': return 'text-amber-400';
            case '绝世天骄': return 'text-red-600';
            default: return 'text-white';
        }
    };

    const getRootGradeColor = (grade: RootGrade) => {
        switch (grade) {
            case '凡人': return 'text-slate-500';
            case '伪灵根': return 'text-gray-400';
            case '下品灵根': return 'text-emerald-600';
            case '中品灵根': return 'text-sky-600';
            case '极品灵根': return 'text-amber-600 font-bold';
            default: return 'text-gray-400';
        }
    };

    const getGradeColor = (grade: number | string | undefined) => {
        if (typeof grade === 'string') return 'border-purple-500 text-purple-400 shadow-[0_0_5px_rgba(168,85,247,0.3)]';
        const g = Number(grade) || 0;
        if (g <= 1) return 'border-slate-300 text-slate-100 bg-slate-500/10 shadow-[0_0_5px_rgba(255,255,255,0.1)]';
        if (g <= 4) return 'border-emerald-500 text-emerald-400 bg-emerald-500/10 shadow-[0_0_8px_rgba(16,185,129,0.2)]';
        if (g <= 6) return 'border-sky-500 text-sky-400 bg-sky-500/10 shadow-[0_0_10px_rgba(14,165,233,0.3)]';
        if (g === 7) return 'border-orange-500 text-orange-400 bg-orange-500/10 shadow-[0_0_12px_rgba(249,115,22,0.4)]';
        if (g >= 8) return 'border-yellow-500 text-yellow-400 bg-yellow-500/10 shadow-[0_0_15px_rgba(234,179,8,0.5)]';
        return 'border-slate-400 text-slate-300';
    };

    const getRealmStyle = (realm: Realm) => {
        if (realm === Realm.Mortal) return "border-[#4a3728] bg-[#2c1810] text-[#8c6b4f]";
        return "border-[#6b4e31] bg-[#3d2b1f] text-[#c9a063]";
    };

    const getRealmText = (realm: Realm, subRealm: number) => {
        if (realm === Realm.Mortal) return '凡人';
        return `${realm}${subRealm}层`;
    };

    const getGradeText = (method: CultivationMethod) => {
        const numerals = ['','一','二','三','四','五','六','七','八','九'];
        return `${numerals[method.grade]}品${method.quality}`;
    };

    const toggleMethod = (methodId: number, type: MethodType) => {
        if (!selectedMember) return;

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
        setFocusedLibraryMethodId(null);
    };

    const getElementColorClass = (key: string, val: number) => {
        if (val === 0) return 'text-gray-600 border-gray-800 opacity-30';
        switch (key) {
            case 'gold': return 'text-yellow-400 border-yellow-500 bg-yellow-500/10';
            case 'wood': return 'text-green-400 border-green-500 bg-green-500/10';
            case 'water': return 'text-blue-400 border-blue-500 bg-blue-500/10';
            case 'fire': return 'text-red-400 border-red-500 bg-red-500/10';
            case 'earth': return 'text-orange-700 border-orange-800 bg-orange-800/10';
            default: return 'text-gray-400 border-gray-500';
        }
    };

    const getElementName = (key: string) => {
        switch (key) {
            case 'gold': return '金';
            case 'wood': return '木';
            case 'water': return '水';
            case 'fire': return '火';
            case 'earth': return '土';
            default: return key;
        }
    };

    const libraryMethods = useMemo(() => {
        if (!selectedMember) return [];
        return CULTIVATION_METHODS.filter(m => {
            if (m.type !== libraryType) return false;
            const isOwnedByClan = (state.inventory.methods[m.name] || 0) > 0;
            const isOwnedBySelf = (selectedMember.personalInventory.methods[m.name] || 0) > 0;
            const isEquipped = selectedMember.mainMethodId === m.id || 
                             selectedMember.movementMethodId === m.id || 
                             selectedMember.auxMethodIds.includes(m.id);
            return isOwnedByClan || isOwnedBySelf || isEquipped;
        }).map(m => {
            const totalCount = (state.inventory.methods[m.name] || 0) + (selectedMember.personalInventory.methods[m.name] || 0);
            return { ...m, totalCount };
        });
    }, [libraryType, selectedMember, state.inventory.methods]);

    const showTooltip = useCallback((e: React.MouseEvent, content: React.ReactNode) => {
        const rect = e.currentTarget.getBoundingClientRect();
        let x = rect.left + rect.width / 2;
        let y = rect.top;

        if (rect.top < 300) {
            y = rect.bottom + 12;
        } else {
            y = rect.top - 12;
        }

        const tooltipWidth = 260;
        if (x - tooltipWidth / 2 < 20) x = tooltipWidth / 2 + 20;
        if (x + tooltipWidth / 2 > window.innerWidth - 20) x = window.innerWidth - tooltipWidth / 2 - 20;

        setTooltip({ content, x, y, visible: true });
    }, []);

    const hideTooltip = useCallback(() => {
        setTooltip(prev => prev ? { ...prev, visible: false } : null);
    }, []);

    const renderMethodTooltipContent = (method: CultivationMethod) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-yellow-500 font-bold text-sm">{method.name}</span>
                <span className={`text-[10px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(method.grade)}`}>
                    {getGradeText(method)}
                </span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{method.desc}</p>
            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-green-500 font-bold mb-1">【功法效果】</p>
                {method.buffs.cultivationSpeed && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">修炼速度</span>
                        <span className={method.buffs.cultivationSpeed > 0 ? 'text-green-400' : 'text-red-400'}>
                            {method.buffs.cultivationSpeed > 0 ? '+' : ''}{method.buffs.cultivationSpeed}%
                        </span>
                    </div>
                )}
                {method.buffs.attack && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">战斗力</span>
                        <span className="text-orange-400">+{method.buffs.attack}%</span>
                    </div>
                )}
                {method.buffs.defense && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">防御力</span>
                        <span className="text-blue-400">+{method.buffs.defense}%</span>
                    </div>
                )}
                {method.buffs.maxAge && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">延寿</span>
                        <span className="text-emerald-400">+{method.buffs.maxAge} 载</span>
                    </div>
                )}
                <p className="text-[9px] text-yellow-600/80 mt-2 italic">"{method.bonus}"</p>
            </div>
        </div>
    );

    const renderItemTooltipContent = (itemName: string) => {
        const details = WEAPON_DETAILS[itemName] || 
                        PILL_DETAILS[itemName] || 
                        HERB_DETAILS[itemName] || 
                        MINERAL_DETAILS[itemName] || 
                        METHOD_DETAILS[itemName];

        if (!details) return (
            <div className="w-52 sm:w-64 font-serif border-2 border-red-900/30 p-2 bg-black/40">
                <span className="text-gray-500 text-xs">未知物品：{itemName}</span>
            </div>
        );

        const gradeStr = (details as any).gradeText || (details.grade ? (typeof details.grade === 'number' ? `${details.grade}品` : details.grade) : '凡物');

        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{itemName}</span>
                    <span className={`text-[9px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(details.grade)}`}>
                        {gradeStr}
                    </span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{details.desc}</p>
                {(details as any).effect && (
                    <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                        <p className="text-[10px] text-orange-400 font-bold mb-1">【物品效果】</p>
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">效果描述</span>
                            <span className="text-gray-200">{(details as any).effect}</span>
                        </div>
                    </div>
                )}
            </div>
        );
    };

    const handleUnequip = (slot: keyof ClanMember['equippedItems']) => {
        if (!selectedMember) return;
        const itemName = selectedMember.equippedItems[slot];
        if (!itemName) return;

        const newEquipped = { ...selectedMember.equippedItems, [slot]: null };
        const newInventory = { ...selectedMember.personalInventory };

        if (slot === 'weapon') {
            newInventory.weapons[itemName] = (newInventory.weapons[itemName] || 0) + 1;
        } else {
            newInventory.weapons[itemName] = (newInventory.weapons[itemName] || 0) + 1;
        }

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedEquipSlot(null);
    };

    const handleEquip = (itemName: string, category: 'weapon' | 'armor' | 'accessory' | 'treasure') => {
        if (!selectedMember) return;

        const newEquipped = { ...selectedMember.equippedItems };
        const newInventory = { ...selectedMember.personalInventory };

        const currentItem = newEquipped[category];
        if (currentItem) {
            newInventory.weapons[currentItem] = (newInventory.weapons[currentItem] || 0) + 1;
        }

        if (newInventory.weapons[itemName] > 0) {
            newInventory.weapons[itemName]--;
            if (newInventory.weapons[itemName] === 0) delete newInventory.weapons[itemName];
        }

        newEquipped[category] = itemName;

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedBagItem(null);
    };

    const handleUsePill = (pillName: string) => {
        if (!selectedMember) return;

        const pillData = PILL_DETAILS[pillName];
        if (!pillData) return;

        const newInventory = { ...selectedMember.personalInventory };
        if (!newInventory.pills[pillName] || newInventory.pills[pillName] <= 0) return;

        newInventory.pills[pillName]--;
        if (newInventory.pills[pillName] === 0) delete newInventory.pills[pillName];

        const updates: Partial<ClanMember> = { personalInventory: newInventory };

        const pillEffects = (pillData as any).effects;
        if (pillEffects) {
            if (pillEffects.cultivationProgress) {
                updates.cultivationProgress = Math.min(100, (selectedMember.cultivationProgress || 0) + pillEffects.cultivationProgress);
            }
            if (pillEffects.status) {
                updates.status = pillEffects.status;
            }
            if (pillEffects.maxAge) {
                updates.maxAge = (selectedMember.maxAge || 0) + pillEffects.maxAge;
            }
            if (pillEffects.divineSense) {
                updates.divineSense = (selectedMember.divineSense || 0) + pillEffects.divineSense;
            }
        }

        onUpdateMember(selectedMember.id, updates);
        setFocusedBagItem(null);
        hideTooltip();
    };

    const renderPhysiqueTooltipContent = (physique: string) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-pink-400 font-bold text-sm">{physique}</span>
                <span className="text-[9px] px-1.5 py-0.5 rounded-sm font-bold border border-pink-900/50 text-pink-500">天赋体质</span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{PHYSIQUE_DETAILS[physique] || '暂无详细记载。'}</p>
            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-pink-500 font-bold mb-1">【先天禀赋】</p>
                <div className="flex justify-between text-[10px]">
                    <span className="text-gray-500">觉醒状态</span>
                    <span className="text-emerald-400">已圆满</span>
                </div>
            </div>
        </div>
    );

    const renderAbilityTooltipContent = (ability: string) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-orange-400 font-bold text-sm">{ability}</span>
                <span className="text-[9px] px-1.5 py-0.5 rounded-sm font-bold border border-orange-900/50 text-orange-500">神通秘术</span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{ABILITY_DETAILS[ability] || '暂无详细记载。'}</p>
            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-orange-500 font-bold mb-1">【神通威力】</p>
                <div className="flex justify-between text-[10px]">
                    <span className="text-gray-500">威能评价</span>
                    <span className="text-orange-300">莫测</span>
                </div>
            </div>
        </div>
    );

    const renderNamePlaque = (member: ClanMember) => (
        <div className={`border-2 border-black bg-red-950/60 px-6 py-2 shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-sm ${member.tier === '绝世天骄' ? 'ring-1 ring-red-500/50' : ''}`}>
            <h2 className="text-xl sm:text-2xl lg:text-3xl font-cursive tracking-wider text-center whitespace-nowrap">
                <span className="text-yellow-400">{member.name}</span>
                {member.title && (
                    <>
                        <span className="mx-1 text-black font-bold">·</span>
                        <span className={`${getTitleColor(member.tier)}`}>{member.title}</span>
                    </>
                )}
            </h2>
        </div>
    );

    const renderSlotItem = (methodId: number | null, type: MethodType, label: string, slotKey: string) => {
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        const isFocused = focusedSlot === slotKey;

        return (
            <div className="flex flex-col items-center gap-1 group relative">
                <div 
                    onClick={() => methodId !== null && setFocusedSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => method && showTooltip(e, renderMethodTooltipContent(method))}
                    onMouseLeave={hideTooltip}
                    className={`relative cursor-pointer transition-all duration-300 rounded-md border flex items-center justify-center 
                        w-12 h-12 sm:w-14 sm:h-14 
                        ${isFocused ? 'border-yellow-500 shadow-[0_0_10px_rgba(234,179,8,0.5)]' : 'border-yellow-900/20'} 
                        bg-black/40 overflow-hidden hover:border-yellow-600/50`}
                >
                    {method ? (
                        <div className={`w-full h-full p-1 flex flex-col items-center justify-center text-center font-bold ${getGradeColor(method.grade)}`}>
                             <span className="text-base sm:text-lg opacity-80 leading-none">📜</span>
                             <span className="text-[7px] sm:text-[8px] leading-tight line-clamp-2 mt-0.5">{method.name}</span>
                        </div>
                    ) : (
                        <div className="text-gray-800 text-[8px] sm:text-[9px] opacity-20 italic font-bold">{label}</div>
                    )}

                    {methodId !== null && isFocused && (
                        <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center p-0.5 animate-fade-in z-20">
                            <button 
                                onClick={(e) => { e.stopPropagation(); if (methodId !== null) toggleMethod(methodId, type); hideTooltip(); }}
                                className="bg-red-900/80 hover:bg-red-700 text-white text-[7px] py-0.5 px-1 rounded-full border border-red-500/50"
                            >
                                卸下
                            </button>
                        </div>
                    )}
                </div>
                <div className="bg-black/60 px-1 py-0.5 rounded-full border border-yellow-900/40 shadow-sm">
                    <span className="text-[7px] sm:text-[8px] text-yellow-500/80 font-bold whitespace-nowrap">{label}</span>
                </div>
            </div>
        );
    };

    const renderEquipSlot = (item: string | null, label: string, icon: string, slotKey: keyof ClanMember['equippedItems']) => {
        const isFocused = focusedEquipSlot === slotKey;
        const isLeftSide = slotKey === 'weapon' || slotKey === 'armor';

        return (
            <div className="flex flex-col items-center gap-1 relative">
                <div 
                    onClick={() => item && setFocusedEquipSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => item && showTooltip(e, renderItemTooltipContent(item))}
                    onMouseLeave={hideTooltip}
                    className={`w-12 h-12 sm:w-16 sm:h-16 rounded border-2 flex items-center justify-center transition-all bg-black/40 hover:border-yellow-500/50 cursor-pointer relative overflow-hidden ${item ? 'border-yellow-600 text-yellow-400 font-bold text-[10px] px-1 text-center shadow-[inset_0_0_15px_rgba(234,179,8,0.15)]' : 'border-white/10 text-gray-800'}`}>
                    {item ? item : icon}
                    {item && isFocused && (
                        <div className="absolute inset-0 border-2 border-yellow-400/60 animate-pulse pointer-events-none"></div>
                    )}
                </div>

                {item && isFocused && (
                    <button 
                        onClick={(e) => { e.stopPropagation(); handleUnequip(slotKey); hideTooltip(); }}
                        className={`absolute top-1/2 -translate-y-1/2 z-30 bg-red-800 hover:bg-red-700 text-white text-[10px] py-1 px-2 rounded-sm font-bold shadow-[0_0_12px_rgba(239,68,68,0.5)] border border-red-500 transition-all active:scale-95 whitespace-nowrap
                            ${isLeftSide ? '-right-10 sm:-right-12' : '-left-10 sm:-left-12'}`}
                    >
                        卸下
                    </button>
                )}

                <span className="text-[10px] text-gray-600 mt-1">{label}</span>
            </div>
        );
    };

    const renderCultivationTab = () => {
        if (!selectedMember) return null;
        return (
            <div className="h-full flex flex-col min-h-0 overflow-hidden animate-fade-in">
                <div className="relative w-full flex-2 items-center justify-center py-4 sm:py-6 bg-black/10 rounded-xl border border-white/5 shadow-xl overflow-hidden mb-2">
                    <div className="absolute inset-0 pointer-events-none opacity-10 flex items-center justify-center">
                         <div className="w-[180px] h-[180px] sm:w-[240px] sm:h-[240px] border border-yellow-900/10 rounded-full animate-[spin_40s_linear_infinite]"></div>
                         <div className="absolute w-[140px] h-[140px] sm:w-[180px] sm:h-[180px] border border-yellow-700/5 rounded-full"></div>
                    </div>

                    <div className="relative grid grid-cols-3 gap-x-4 sm:gap-x-12 gap-y-2 sm:gap-y-4 z-10 items-center">
                        <div className="flex flex-col gap-4 sm:gap-6">
                            {renderSlotItem(selectedMember.auxMethodIds[0] || null, 'Combat', '辅修I', 'aux0')}
                            {renderSlotItem(selectedMember.auxMethodIds[1] || null, 'Combat', '辅修II', 'aux1')}
                        </div>

                        <div className="flex flex-col items-center gap-2 sm:gap-3">
                            {renderSlotItem(selectedMember.movementMethodId, 'Movement', '遁术', 'mov')}

                            <div className="w-10 h-10 sm:w-15 sm:h-15 rounded-full bg-yellow-900/5 border border-yellow-500/10 flex items-center justify-center relative">
                                <span className="text-lg sm:text-xl opacity-30">🧘</span>
                                <div className="absolute inset-0 rounded-full border-t border-yellow-500/20 animate-spin"></div>
                            </div>

                            {renderSlotItem(selectedMember.mainMethodId, 'Cultivation', '主修', 'main')}
                        </div>

                        <div className="flex flex-col gap-4 sm:gap-6">
